  readonly type: "hoard_taken";
  readonly data: {
    readonly featureId: string;
    readonly name: string;
    readonly depth: number;
    readonly position: Position;
  };
};

export type RunCustomEvent =
  | RunActionResolvedEvent
  | RunActionIllegalEvent
  | RunFloorEnteredEvent
  | RunPlacementDeviationEvent
  | RunBoredomEvent
  | RunReinforcementSpawnedEvent
  | HoardTakenEvent;

export type RunEvent = TurnEvent | RunCustomEvent;

export const runEvent = <Type extends RunCustomEvent["type"]>(
  turn: number,
  type: Type,
  data: Extract<RunCustomEvent, { readonly type: Type }>["data"]
): Extract<RunCustomEvent, { readonly type: Type }> =>
  ({
    turn,
    type,
    data
  }) as Extract<RunCustomEvent, { readonly type: Type }>;

export const appendRunLog = (
  state: GameState,
  events: readonly RunEvent[]
): GameState => ({
  ...state,
  log: [...state.log, ...(events as readonly EngineLogEvent[])]
});

