    return null;
  }

  const placement = placements.find(
    (candidate) => candidate.requestId === hoard.request.id
  );
  if (placement === undefined) {
    return null;
  }

  return {
    id: hoard.params.id,
    name: hoard.params.name,
    position: placement.position
  };
};

