export const evaluateBehaviors = (
  state: GameState,
  enemyId: EntityId,
  rng: Rng | AiRngContext = aiRngContextFor(state),
): BehaviorAction => {
  const enemy = state.entities[enemyId];
  const context = isAiRngContext(rng) ? rng : aiRngContextFor(state);

  if (enemy?.kind !== "enemy") {
    return { kind: "wait" };
