const applyPlayerAction = (
  state: GameState,
  action: PlayerAction,
): ActionResolverResult => {
  if (action.kind === "abort") {
    const status = config.runStructure.terminalStates.abort;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player aborted the run",
        }),
      ],
    };
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= config.runStructure.depthFloors
  ) {
    const status = config.runStructure.terminalStates.win;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player descended from the final floor",
        }),
      ],
    };
  }

  if (action.kind === "wait") {
    return {
      state,
      events: [],
    };
  }

  if (isActionResolverAction(action)) {
    return applyRegisteredActionResolver(state, action);
  }

  return {
    state,
    events: [],
  };
};

const applyRegisteredActionResolver = (
  state: GameState,
  action: ActionResolverAction,
): ActionResolverResult => {
  const resolver = actionResolvers.get(action.kind);

  if (resolver === undefined) {
    return {
      illegal: true,
      reason: "no handler registered",
    };
  }

  return resolver(state, action);
};

const isActionResolverAction = (
  action: PlayerAction,
): action is ActionResolverAction => {
  switch (action.kind) {
    case "move":
    case "attack":
    case "use_item":
    case "pickup":
    case "talk":
    case "inspect":
      return true;
    case "wait":
    case "descend":
    case "abort":
      return false;
  }
};

const isActionResolverIllegal = (
  result: ActionResolverResult,
): result is ActionResolverIllegal => "illegal" in result;

const forcedTerminalFor = (
  state: GameState,
): { readonly status: Exclude<TerminalStatus, "ACTIVE">; readonly reason: string } | null => {
  if (state.player.hp.current <= 0) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: "player HP reached 0",
    };
  }

  if (state.run.turn >= bounds.runStructure.perRunHardCapTurns) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: `run hard cap reached at ${bounds.runStructure.perRunHardCapTurns} turns`,
    };

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

const checkUseItemAction = (
  state: GameState,
  action: UseItemAction,
): ActionLegality => {
  if (
    !state.player.inventory.some(
      (slot) => slot?.itemInstanceId === action.itemId,
    )
  ) {
    return illegal(`item ${action.itemId} is not carried`);
  }

  if (action.target === undefined || action.target.kind === "self") {
    return action.direction === undefined ||
      MOVE_DIRECTIONS.some((entry) => entry.direction === action.direction)
      ? LEGAL_ACTION
      : illegal(`unknown use direction ${action.direction}`);
  }

  if (action.target.kind === "entity") {
    return state.entities[action.target.entityId] === undefined
      ? illegal(`target entity ${action.target.entityId} does not exist`)
      : LEGAL_ACTION;
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.target.cell)
    ? LEGAL_ACTION
    : illegal(
        `target cell (${action.target.cell.x}, ${action.target.cell.y}) is outside the map`,
      );
};

const checkPickupAction = (state: GameState): ActionLegality => {
  if (!state.player.inventory.some((slot) => slot === null)) {
    return illegal("inventory is full");
  }

  return sortedEntities(state).some(
    (entity) =>
      entity.kind === "item" &&
      samePosition(entity.position, state.player.position),
  )
    ? LEGAL_ACTION
    : illegal("there is no item here to pick up");
};

